attachments.value:
{%- set data = engine.query_stream_data(stream="ai_mcp_toolsets") -%}
{%- set toolset_name = toolset_name -%}
{%- set version = version | default(current_version) -%}

{%- set config_data_for_toolset =
    data | selectattr("toolset_name", "equalto", toolset_name) | list
-%}

{%- if ai_project_name -%}
  {%- set config_data_for_toolset =
      config_data_for_toolset
      | selectattr("ai_project_name", "equalto", ai_project_name)
      | list
  -%}
{%- endif -%}

{# Grab raw contents (may be string OR dict/list) #}
{%- set lhs_raw =
    config_data_for_toolset
    | selectattr("version", "equalto", version)
    | map(attribute="contents")
    | list
    | first
-%}

{%- set rhs_raw =
    config_data_for_toolset
    | selectattr("version", "equalto", compare_version)
    | map(attribute="contents")
    | list
    | first
-%}

<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Toolset Diff Viewer</title>

  <style>
    html, body {
      margin: 0;
      padding: 0;
      height: 100%;
      width: 100%;
      background: #1e1e2f;
      color: #ffffff;
      font-family: "Segoe UI", Roboto, sans-serif;
    }

    #header {
      background: #2b2b3d;
      border-bottom: 1px solid #3a3a4d;
      padding: 10px 0;
      text-align: center;
    }

    #header .title {
      font-size: 18px;
      font-weight: 600;
    }

    #header .project {
      color: #7dcfff;
      font-size: 15px;
      margin-top: 3px;
    }

    #version-row {
      display: grid;
      grid-template-columns: 1fr 1fr;
      background: #24243a;
      border-bottom: 1px solid #3a3a4d;
      padding: 6px 20px;
      font-size: 14px;
      color: #c8c8dc;
      font-weight: 500;
      gap: 10px;
    }

    .version-label span {
      color: #7dcfff;
      font-weight: 600;
    }

    #diff-container {
      height: calc(100% - 110px);
      width: 100%;
    }
  </style>

  <script src="https://cdnjs.cloudflare.com/ajax/libs/require.js/2.3.6/require.min.js"></script>
</head>

<body>
  <div id="header">
    <div class="title">
      Toolset Difference for: <span>{{ toolset_name }}</span>
    </div>
    {% if ai_project_name %}
      <div class="project">Project: {{ ai_project_name }}</div>
    {% endif %}
  </div>

  <div id="version-row">
    <div class="version-label">
      Current Version: <span>{{ version }}</span>
    </div>
    <div class="version-label">
      Comparison Version: <span>{{ compare_version }}</span>
    </div>
  </div>

  <div id="diff-container"></div>

  <script>
    // NOTE:
    // lhs_raw / rhs_raw can be:
    // - a string (already YAML/JSON text)
    // - an object/array (structured toolset contents)
    //
    // We inject them as JS values using tojson, then normalize to strings.
    const lhs_raw = {{ lhs_raw | default(none) | tojson }};
    const rhs_raw = {{ rhs_raw | default(none) | tojson }};

    function normalizeToText(v) {
      if (v === null || v === undefined) return "";
      if (typeof v === "string") return v;
      try {
        return JSON.stringify(v, null, 2);
      } catch (e) {
        // Last resort
        return String(v);
      }
    }

    const lhs = normalizeToText(lhs_raw);
    const rhs = normalizeToText(rhs_raw);

    window.require.config({
      paths: {
        vs: "https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs"
      }
    });

    window.require(["vs/editor/editor.main"], function () {
      const container = document.getElementById("diff-container");

      if (!lhs || !rhs) {
        container.innerText =
          "Missing toolset data. Please ensure both versions exist and contain contents.";
        return;
      }

      // Choose language: YAML if it looks like YAML, else JSON.
      // (Monaco will still work fine even if this guess is imperfect.)
      const looksYaml = (s) =>
        /^[\s-]*[A-Za-z0-9_.-]+\s*:\s*/m.test(s) && !/^\s*[\[{]/.test(s.trim());
      const lang = (looksYaml(lhs) || looksYaml(rhs)) ? "yaml" : "json";

      const originalModel = monaco.editor.createModel(lhs, lang);
      const modifiedModel = monaco.editor.createModel(rhs, lang);

      const diffEditor = monaco.editor.createDiffEditor(container, {
        theme: "vs-dark",
        readOnly: true,
        automaticLayout: true,
        enableSplitViewResizing: true
      });

      diffEditor.setModel({
        original: originalModel,
        modified: modifiedModel
      });
    });
  </script>
</body>
</html>
